# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.common.keys import Keys
import boto3

app = Flask(__name__)

# AWS S3 client
s3 = boto3.client('s3')

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json['url']

    # Create a headless Chrome driver
    driver = webdriver.Chrome(executable_path='chromedriver')
    driver.get(url)

    # Take a screenshot
    screenshot = driver.get_screenshot_as_png()

    # Close the driver
    driver.quit()

    # Upload the screenshot to S3
    s3.put_object(Bucket='screenshot-bucket', Key=f'{url}.png', Body=screenshot)

    # Return the S3 URL of the screenshot
    return jsonify({'screenshot_url': f's3://screenshot-bucket/{url}.png'})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)